mapper.select:

SELECT *
FROM 
	EXAM_STUDENT_ANSWER_DETAIL
WHERE
	1=1


AND ID=#{id}


AND STUDENT_ANSWER_ID=#{studentAnswerId}


AND QUESTION_ID=#{questionId}


AND ANSWER_CONTENT=#{answerContent}


AND SCORE=#{score}


AND REVIEWER_ID=#{reviewerId}


AND REVIEW_DATE=#{reviewDate}

ORDER BY ID

SELECT STUDENT_ANSWER_ID as SAID, COUNT(1) as ANUM FROM EXAM_STUDENT_ANSWER_DETAIL WHERE ANSWER_CONTENT IS NOT NULL and STUDENT_ANSWER_ID IN
#{id}
GROUP BY STUDENT_ANSWER_ID

SELECT STUDENT_ANSWER_ID as SAID, SUM(SCORE) as ASCORE FROM EXAM_STUDENT_ANSWER_DETAIL WHERE SCORE IS NOT NULL and STUDENT_ANSWER_ID IN
#{id}
GROUP BY STUDENT_ANSWER_ID
